package pe.org.camaracomercioica.protestos.security; import jakarta.servlet.http.*; import org.springframework.security.oauth2.server.resource.web.BearerTokenResolver; import org.springframework.security.oauth2.server.resource.web.DefaultBearerTokenResolver; public class CookieBearerTokenResolver implements BearerTokenResolver {private final DefaultBearerTokenResolver header=new DefaultBearerTokenResolver();private final String cookieName;public CookieBearerTokenResolver(String cookieName){this.cookieName=cookieName;}public String resolve(HttpServletRequest request){String token=header.resolve(request);if(token!=null)return token;if(request.getCookies()!=null)for(Cookie c:request.getCookies())if(cookieName.equals(c.getName()))return c.getValue();return null;}}